INSERT INTO genres (id, name, slug, parent_id, description, is_speculative) VALUES
  (1, 'Science Fiction', 'science-fiction', NULL, 'Speculation driven by science, engineering, space, time, and the consequences of technology.', 1),
  (2, 'Hard SF', 'hard-sf', 1, 'Sticks closely to known science/engineering and extrapolates carefully.', 1),
  (3, 'Engineering SF', 'engineering-sf', 2, 'Plots hinge on building, fixing, or optimizing complex technical systems.', 1),
  (4, 'Scientific Problem-Solving SF', 'scientific-problem-solving-sf', 2, 'Characters tackle puzzles grounded in physics, biology, or math.', 1),
  (5, 'Soft SF', 'soft-sf', 1, 'Focuses more on psychology, sociology, anthropology, and culture than equations.', 1),
  (6, 'Social SF', 'social-sf', 5, 'Examines how societies change under new conditions or inventions.', 1),
  (7, 'Anthropological SF', 'anthropological-sf', 5, 'Uses alien cultures or future peoples to explore human assumptions.', 1),
  (8, 'Space Opera', 'space-opera', 1, 'Big-emotion, big-scale adventures across star systems with politics and war.', 1),
  (9, 'Military Space Opera', 'military-space-opera', 8, 'Fleet tactics, campaigns, and soldiers’ lives in interstellar conflict.', 1),
  (10, 'Political Space Opera', 'political-space-opera', 8, 'Empires, diplomacy, revolutions, and governance as the core engine.', 1),
  (11, 'Military SF', 'military-sf', 1, 'War stories where future tech reshapes strategy and ethics.', 1),
